(function () { let set = new Set(); set.add("a"); set.add("b"); let values = set.values(); let v1 = values.next(); let v2 = values.next(); let v3 = values.next(); let entries = set.entries(); let e1 = entries.next(); let keys = set.keys(); let seen = ""; set.forEach(function (value, key, receiver) { seen += key + "=" + value + ":" + (receiver === set) + "|"; }); return v1.value + ":" + v1.done + "|" + v2.value + ":" + v2.done + "|" + v3.done + ":" + (v3.value === undefined) + "|" + e1.value[0] + ":" + e1.value[1] + "|" + keys.next().value + "|" + seen; })()
